## Code Example

```javascript
class Cache {
  constructor(ttlMs) { this.ttl = ttlMs; this.map = new Map(); }
  async get(key, fetcher) {
    const now = Date.now();
    const rec = this.map.get(key);
    if (rec && now - rec.ts < this.ttl) return rec.value;
    const value = await fetcher(key);
    this.map.set(key, { value, ts: now });
    return value;
  }
}
```

