## Code Example
```javascript
function debounce(fn, wait) {
  let t;
  return function(...args) {
    clearTimeout(t);
    t = setTimeout(() => fn.apply(this, args), wait);
  };
}

test('debounce calls only once with last args', () => {
  jest.useFakeTimers();
  const mock = jest.fn();
  const debounced = debounce(mock, 100);
  debounced(1);
  debounced(2);
  debounced(3);
  jest.advanceTimersByTime(100);
  expect(mock).toHaveBeenCalledTimes(1);
  expect(mock).toHaveBeenCalledWith(3);
});
```

