function signup(req, res, db, emailService) {
  const idempotencyKey = req.headers['Idempotency-Key'];

  // Check for existing request
  const existingResult = await db.getResult(idempotencyKey);
  if (existingResult) {
    return res.status(200).json(existingResult);
  }

  // Validate input and create user
  const user = await validateAndCreateUser(req.body);

  // Send email with retry logic
  try {
    await emailService.sendVerification(user.email);
  } catch (error) {
    // Handle email failure with retry queue
  }

  // Store result with idempotency key
  const result = { userId: user.id, status: 'created' };
  await db.storeResult(idempotencyKey, result);

  return res.status(201).json(result);
}
```

