// Pseudo-test: seed-based synthetic data generator for
// deterministic mobile event production
const generateMobileEvents = (seed, count) => {
  const rng = seededRandom(seed);
  return Array.from({length: count}, () => ({
    eventId: uuidv5(`${rng()}-event`, NAMESPACE),
    userId: `user_${Math.floor(rng() * 1000000)}`,
    timestamp: Date.now() + Math.floor(rng() * 1000),
    eventType: SAMPLE_EVENTS[Math.floor(rng() * SAMPLE_EVENTS.length)],
