// __tests__/upsert.test.js
const db = require('../../src/db');
const { upsertUser } = require('../../src/user-service');

describe('User Upsert', () => {
  beforeAll(async () => {
    await db.connect();
    await db.query('DELETE FROM users');
  });

  afterAll(async () => {
    await db.disconnect();
  });

  test('inserts new user when not exists', async () => {
    const user = { id: '1', name: 'Bob', email: 'bob@example.com' };
    const result = await upsertUser(user, 'key-1');

    expect(result.status).toBe('inserted');
    const count = await db.query('SELECT COUNT(*) FROM users');
    expect(count).toBe(1);
  });

  test('idempotency: duplicate key returns success without re-inserting', async () => {
    const user = { id: '2', name: 'Carol', email: 'carol@example.com' };

    const first = await upsertUser(user, 'key-2');
    expect(first.status).toBe('inserted');

    const second = await upsertUser(user, 'key-2');
    expect(second.status).toBe('already_processed');

    const count = await db.query('SELECT COUNT(*) FROM users WHERE id = 2');
    expect(count).toBe(1); // Still only one record
  });
});
```

