describe('Concurrent Ingestion', () => {
  test('handles 10 concurrent invocations correctly', async () => {
    const records = Array.from({ length: 100 }, (_, i) => ({
      id: String(i),
      name: `User ${i}`,
      email: `user${i}@test.com`
    }));

    const invocations = records.map((record, i) => 
      processCSV(record, `invocation-${i}`)
    );

    const results = await Promise.all(invocations);

    // All succeed (no duplicates cause errors)
    results.forEach(r => {
      expect(['inserted', 'already_processed']).toContain(r.status);
