    expect(totalUsers).toBe(100);
  });
});
```

```javascript
// __tests__/outage-retry.test.js
const { simulateOutage, restore } = require('../helpers/db-mock');

describe('Retry on DB Outage', () => {
  test('retries with exponential backoff after outage', async () => {
    let attempt = 0;
    const mockDb = {
      query: jest.fn(() => {
        attempt++;
        if (attempt < 3) throw new Error('Connection lost');
        return { rows: [] };
      })
    };

    const start = Date.now();
    await withRetry(() => mockDb.query('SELECT 1'), {
      maxRetries: 3,
      backoff: 'exponential'
    });
    const elapsed = Date.now() - start;

    expect(attempt).toBe(3);
    expect(elapsed).toBeGreaterThan(300); // ~100ms + 200ms backoff
  });
});
