## Code Example
```javascript
class Cache {
  constructor(ttlMs) {
    this.ttl = ttlMs;
    this.map = new Map();
  }

  set(k, v) {
    this.map.set(k, { v, exp: Date.now() + this.ttl });
  }

  get(k) {
    const entry = this.map.get(k);
    if (!entry) return null;
    if (Date.now() > entry.exp) {
      this.map.delete(k);
      return null;
    }
    return entry.v;
  }
}```

