// Idempotent guard: check if file was already processed
async function handleEvent(event, db, s3) {
  const bucket = event.bucket;
  const key = event.key;

  const readStream = await s3.getObject(bucket, key).createReadStream();
  const checksum = await computeChecksum(readStream);

  const existing = await db.get(`FILE#${checksum}`);
  if (existing) {
    return { statusCode: 200, body: 'Already processed' };
  }

  await processChunks(readStream, db, checksum);
  await db.put(`FILE#${checksum}`, { processedAt: Date.now() });
}
```

