## Code Example

```javascript
// Jest/Vitest with fake timers
jest.useFakeTimers();

describe('User Cache', () => {
  const backend = new MockBackend();
  const cache = new InMemoryCache(60); // 60 second TTL

  test('populates cache on first request', async () => {
    const result = await cache.get('user1', () => backend.fetch('user1'));
    expect(backend.callCount).toBe(1);
    expect(result).toEqual(backend.response);
  });

  test('returns cached value within TTL', async () => {
    await cache.get('user1', () => backend.fetch('user1'));
    const cached = await cache.get('user1', () => backend.fetch('user1'));
    expect(backend.callCount).toBe(1); // backend called only once
  });

  test('expires after TTL', async () => {
    await cache.get('user1', () => backend.fetch('user1'));
    jest.advanceTimersByTime(61000); // 61 seconds
    await cache.get('user1', () => backend.fetch('user1'));
    expect(backend.callCount).toBe(2); // cache expired, backend called again
  });

  test('handles concurrent requests (no stampede)', async () => {
    const promises = Array(10).fill().map(() => 
      cache.get('user1', () => backend.fetch('user1'))
    );
    await Promise.all(promises);
    expect(backend.callCount).toBe(1); // only one backend call
  });
});
```

