## Code Example

```javascript
// Simple in-memory deduplication for messages
function deduplicate(messages) {
  const seen = new Set();
  const unique = [];

  for (const msg of messages) {
    if (!seen.has(msg.id)) {
      seen.add(msg.id);
      unique.push(msg);
    }
  }

  return unique;
}

// Consumer with exactly-once processing
async function processMessage(msg, db) {
  const tx = await db.beginTransaction();

  try {
    // Check if already processed
    const existing = await db.query(
      'SELECT id FROM processed_messages WHERE id = ?',
      [msg.id]
    );

    if (existing.length > 0) {
      await tx.rollback();
      return { status: 'duplicate', skipped: true };
    }

    // Process the message
    await processPayload(msg.payload);

    // Record the message as processed
    await db.execute(
      'INSERT INTO processed_messages (id, processed_at) VALUES (?, NOW())',
      [msg.id]
    );

    await tx.commit();
    return { status: 'processed' };
  } catch (error) {
    await tx.rollback();
    throw error;
  }
}
```

